/**
 * ModeIndicator Component
 * Displays current mode and switching shortcut
 */

export class ModeIndicator {
  private container: HTMLElement;
  private element: HTMLElement | null = null;
  private clickHandler: (() => void) | null = null;

  constructor(container: HTMLElement) {
    this.container = container;
  }

  onClick(handler: () => void): void {
    this.clickHandler = handler;
    if (this.element) {
      this.element.style.cursor = 'pointer';
    }
  }

  update(mode: 'galaxy' | 'foggy-mirror' | 'cosmic-slash'): void {
    if (!this.element) {
      this.createDOM();
    }

    if (!this.element) return;

    const content = this.element.querySelector('.mode-content');
    if (!content) return;

    const modeName =
      mode === 'galaxy'
        ? 'Interactive Galaxy'
        : mode === 'cosmic-slash'
        ? 'Cosmic Slash'
        : 'Foggy Mirror';

    content.innerHTML = `
      <div class="current-mode">${modeName}</div>
      <div class="switch-hint desktop-hint">Press <kbd>M</kbd> for Main Menu</div>
      <div class="switch-hint mobile-hint">Tap for Main Menu</div>
    `;
  }

  private createDOM(): void {
    this.element = document.createElement('div');
    this.element.className = 'mode-indicator';
    this.element.innerHTML = `
      <div class="mode-content"></div>
    `;

    if (this.clickHandler) {
      this.element.style.cursor = 'pointer';
    }

    this.element.addEventListener('click', () => {
      if (this.clickHandler) {
        this.clickHandler();
      }
    });

    const style = document.createElement('style');
    style.textContent = `
      .mode-indicator {
        position: absolute;
        top: 20px;
        left: 20px;
        padding: 16px 20px;
        background: #141414;
        border: 1px solid #222;
        color: #fff;
        font-family: 'Space Grotesk', system-ui, sans-serif;
        border-radius: 8px;
        z-index: 100;
        min-width: 180px;
        transition: all 0.15s ease;
      }

      .mode-indicator:hover {
        background: #1a1a1a;
        border-color: #333;
      }

      @media (max-width: 768px) {
        .mode-indicator {
          top: 14px;
          left: 14px;
          padding: 12px 16px;
          min-width: 0;
        }
        .current-mode { font-size: 13px; margin-bottom: 0; }
        .desktop-hint { display: none !important; }
        .mobile-hint { display: flex !important; }
      }

      .current-mode {
        font-family: 'Space Grotesk', system-ui, sans-serif;
        font-size: 14px;
        font-weight: 600;
        color: #fff;
        margin-bottom: 8px;
        letter-spacing: 0.5px;
      }

      .switch-hint {
        font-size: 12px;
        color: #666;
        padding-top: 8px;
        border-top: 1px solid #222;
        display: flex;
        align-items: center;
        gap: 6px;
      }

      .mobile-hint {
        display: none;
      }

      .switch-hint kbd {
        display: inline-block;
        padding: 2px 6px;
        background: #222;
        border: 1px solid #333;
        border-radius: 4px;
        font-family: 'Space Grotesk', system-ui, sans-serif;
        font-weight: 600;
        font-size: 11px;
        color: #fff;
        min-width: 18px;
        text-align: center;
      }
    `;
    this.element.appendChild(style);
    this.container.appendChild(this.element);
  }
}
