/**
 * LandingPage Component
 * Displays the initial mode selection screen
 */

export type InteractionMode = 'galaxy' | 'foggy-mirror' | 'cosmic-slash';

export class LandingPage {
  private container: HTMLElement;
  private element: HTMLElement | null = null;
  private onSelect: (mode: InteractionMode) => void;
  private isVisible: boolean = false;

  constructor(
    container: HTMLElement,
    onSelect: (mode: InteractionMode) => void
  ) {
    this.container = container;
    this.onSelect = onSelect;
  }

  /**
   * Show the landing page
   */
  show(): void {
    if (this.isVisible) return;

    this.element = document.createElement('div');
    this.element.className = 'landing-page';
    this.element.innerHTML = `
      <div class="landing-container">
        <header class="landing-header">
          <h1 class="app-title">Gesture Lab</h1>
          <p class="app-subtitle">Touchless Interactive Experiences</p>
        </header>
        
        <div class="portals-container">
          <button class="portal-card galaxy-portal" data-mode="galaxy">
            <div class="portal-content">
              <h2 class="portal-title">Interactive Galaxy</h2>
              <p class="portal-desc">Manipulate a universe of particles</p>
            </div>
            <div class="portal-footer">
              <span class="key-hint">Press <kbd>G</kbd></span>
            </div>
            <div class="portal-bg"></div>
          </button>
          
          <button class="portal-card fog-portal" data-mode="foggy-mirror">
            <div class="portal-content">
              <h2 class="portal-title">Foggy Mirror</h2>
              <p class="portal-desc">Clear the mist to reveal reality</p>
            </div>
            <div class="portal-footer">
              <span class="key-hint">Press <kbd>F</kbd></span>
            </div>
            <div class="portal-bg"></div>
          </button>
          
          <button class="portal-card slash-portal" data-mode="cosmic-slash">
            <div class="portal-content">
              <h2 class="portal-title">Cosmic Slash</h2>
              <p class="portal-desc">Slice through cosmic anomalies with your hands</p>
            </div>
            <div class="portal-footer">
              <span class="key-hint">Press <kbd>C</kbd></span>
            </div>
            <div class="portal-bg"></div>
          </button>
        </div>

      </div>
    `;

    // Add styles
    const style = document.createElement('style');
    style.id = 'landing-page-style';
    style.textContent = `
      .landing-page {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: #0a0a0a;
        background-image: 
          radial-gradient(circle at 50% 0%, rgba(40, 40, 60, 0.15) 0%, transparent 50%),
          radial-gradient(circle at 80% 80%, rgba(30, 30, 40, 0.08) 0%, transparent 40%);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 1000;
        opacity: 0;
        transition: opacity 0.6s ease;
        font-family: 'Space Grotesk', system-ui, sans-serif !important;
        overflow: hidden;
      }

      .landing-page * {
        font-family: 'Space Grotesk', system-ui, sans-serif !important;
      }
      
      .landing-page.visible {
        opacity: 1;
      }

      .landing-container {
        text-align: center;
        width: 100%;
        max-width: 600px;
        height: 100%;
        padding: 4rem 2rem;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: space-between;
      }

      .landing-header {
        animation: fadeDown 0.8s ease-out forwards;
      }

      .app-title {
        font-family: 'Space Grotesk', system-ui, sans-serif !important;
        font-size: 2.5rem;
        font-weight: 600;
        letter-spacing: 0.5px;
        margin: 0;
        color: #fff;
      }

      .app-subtitle {
        font-size: 0.9rem;
        color: #666;
        margin-top: 0.5rem;
        font-weight: 400;
        letter-spacing: 0.05rem;
      }

      .portals-container {
        display: flex;
        flex-direction: column;
        gap: 1.5rem;
        width: 100%;
        perspective: 1000px;
        margin: auto 0; /* Center vertically if space allows */
      }

      .portal-card {
        position: relative;
        width: 100%;
        height: auto;
        min-height: 100px;
        background: #141414;
        border: 1px solid #222;
        border-radius: 8px;
        padding: 1.5rem 2rem;
        cursor: pointer;
        transition: all 0.15s ease;
        display: flex;
        flex-direction: row;
        align-items: center;
        justify-content: space-between;
        text-align: left;
        overflow: hidden;
        animation: fadeUp 0.8s ease-out forwards;
        animation-delay: 0.2s;
        opacity: 0;
      }

      .portal-card:nth-child(2) {
        animation-delay: 0.3s;
      }

      .portal-bg {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        z-index: -1;
        opacity: 0;
        transition: opacity 0.4s ease;
      }

      .galaxy-portal .portal-bg {
        background: linear-gradient(90deg, rgba(100, 50, 255, 0.1), transparent);
      }

      .fog-portal .portal-bg {
        background: linear-gradient(90deg, rgba(200, 200, 220, 0.1), transparent);
      }

      .slash-portal .portal-bg {
        background: linear-gradient(90deg, rgba(255, 100, 100, 0.1), transparent);
      }

      .portal-card:hover {
        background: #1a1a1a;
        border-color: #333;
      }

      .portal-card:hover .portal-bg {
        opacity: 1;
      }

      .portal-content {
        z-index: 2;
        flex: 1;
      }

      .portal-title {
        font-size: 1.1rem;
        font-weight: 600;
        color: #fff;
        margin: 0 0 0.25rem 0;
        letter-spacing: 0.5px;
      }

      .portal-desc {
        font-size: 0.85rem;
        color: #666;
        margin: 0;
        font-weight: 400;
      }

      .portal-footer {
        z-index: 2;
        margin-left: 2rem;
        display: flex;
        align-items: center;
      }

      .key-hint {
        font-size: 0.75rem;
        color: #666;
        text-transform: uppercase;
        letter-spacing: 0.05rem;
        display: flex;
        align-items: center;
        gap: 0.5rem;
      }

      kbd {
        background: #222;
        border: 1px solid #333;
        border-radius: 4px;
        padding: 2px 8px;
        color: #fff;
        font-family: 'Space Grotesk', system-ui, sans-serif;
        font-weight: 600;
        font-size: 0.8rem;
        min-width: 24px;
        text-align: center;
      }

      @keyframes fadeDown {
        from { opacity: 0; transform: translateY(-20px); }
        to { opacity: 1; transform: translateY(0); }
      }

      @keyframes fadeUp {
        from { opacity: 0; transform: translateY(20px); }
        to { opacity: 1; transform: translateY(0); }
      }

      @media (max-width: 600px) {
        .landing-container {
          padding: 2rem 1rem;
          gap: 1.5rem;
        }
        .app-title { font-size: 2.5rem; }
        .app-subtitle { font-size: 0.9rem; }
        .portals-container { gap: 1rem; }
        .portal-card { 
          flex-direction: column; 
          align-items: flex-start; 
          gap: 0.5rem;
          padding: 1.2rem;
          min-height: auto;
        }
        .portal-title { font-size: 1.2rem; }
        .portal-desc { font-size: 0.85rem; }
        .portal-footer { display: none; }
      }
    `;
    this.element.appendChild(style);

    this.container.appendChild(this.element);

    // Trigger reflow for transition
    requestAnimationFrame(() => {
      if (this.element) {
        this.element.classList.add('visible');
      }
    });

    this.attachListeners();
    this.isVisible = true;
  }

  /**
   * Hide and remove the landing page
   */
  hide(): void {
    if (!this.isVisible || !this.element) return;

    this.element.classList.remove('visible');

    setTimeout(() => {
      if (this.element && this.element.parentNode) {
        this.element.parentNode.removeChild(this.element);
      }
      this.element = null;
      this.isVisible = false;
    }, 600);
  }

  private attachListeners(): void {
    if (!this.element) return;

    const cards = this.element.querySelectorAll('.portal-card');
    cards.forEach((card) => {
      card.addEventListener('click', () => {
        const mode = card.getAttribute('data-mode') as InteractionMode;
        if (mode) {
          this.onSelect(mode);
        }
      });
    });
  }
}
